{
  "questionNo": "7",
  "type": "7_Where",
  "question": {
    "en": "Where is the conference being held?",
    "vi": "Hội nghị đang được tổ chức ở đâu vậy?"
  },
  "options": [
    {
      "label": "A",
      "en": "A three-day vacation.",
      "vi": "Một kỳ nghỉ kéo dài ba ngày."
    },
    {
      "label": "B",
      "en": "At the Riverview Hotel.",
      "vi": "Tại khách sạn Riverview."
    },
    {
      "label": "C",
      "en": "In the supply cabinet.",
      "vi": "Trong tủ đựng đồ dùng văn phòng."
    }
  ],
  "correctAnswer": "B",
  "explanation": {
    "correct": {
      "why": "Câu hỏi bắt đầu bằng 'Where' (Ở đâu), đáp án B cung cấp một địa điểm cụ thể (khách sạn Riverview) phù hợp để tổ chức sự kiện."
    },
    "incorrect": [
      {
        "label": "A",
        "why": "Đây là câu trả lời về khoảng thời gian (duration), không phải địa điểm.",
        "context_intro": "Câu này sẽ ĐÚNG nếu câu hỏi là:",
        "suggested_question": {
          "en": "How long is your summer break?",
          "vi": "Kỳ nghỉ hè của bạn kéo dài bao lâu?"
        },
        "text": {
          "en": "A three-day vacation.",
          "vi": "Một kỳ nghỉ kéo dài ba ngày."
        }
      },
      {
        "label": "C",
        "why": "Mặc dù chỉ địa điểm nhưng nội dung phi logic (hội nghị không thể tổ chức trong tủ đựng đồ). Đây là bẫy về nhóm từ vựng văn phòng.",
        "context_intro": "Câu này sẽ ĐÚNG nếu câu hỏi là:",
        "suggested_question": {
          "en": "Where do we keep the extra printer paper?",
          "vi": "Chúng ta để giấy in dự phòng ở đâu nhỉ?"
        },
        "text": {
          "en": "In the supply cabinet.",
          "vi": "Trong tủ đựng đồ dùng văn phòng."
        }
      }
    ],
    "vocabulary": [
      {
        "word": "hold (a conference)",
        "ipa": "/həʊld/",
        "meaning": "tổ chức (hội nghị)"
      },
      {
        "word": "supply cabinet",
        "ipa": "/səˈplaɪ ˈkæbɪnət/",
        "meaning": "tủ đựng văn phòng phẩm"
      }
    ]
  }
}

{
  "questionNo": "8",
  "type": "6_When",
  "question": {
    "en": "When does the warehouse manager arrive?",
    "vi": "Khi nào thì quản lý kho hàng đến?"
  },
  "options": [
    {
      "label": "A",
      "en": "Sure, no problem.",
      "vi": "Chắc chắn rồi, không vấn đề gì."
    },
    {
      "label": "B",
      "en": "About twelve shipping boxes.",
      "vi": "Khoảng 12 thùng hàng."
    },
    {
      "label": "C",
      "en": "Not until this afternoon.",
      "vi": "Phải đến tận chiều nay."
    }
  ],
  "correctAnswer": "C",
  "explanation": {
    "correct": {
      "why": "Câu hỏi 'When' tìm kiếm thông tin thời gian. Cấu trúc 'Not until...' là cách trả lời phổ biến để nhấn mạnh thời điểm sự việc xảy ra."
    },
    "incorrect": [
      {
        "label": "A",
        "why": "Đây là câu trả lời chấp nhận một lời nhờ vả hoặc đề nghị.",
        "context_intro": "Câu này sẽ ĐÚNG nếu câu hỏi là:",
        "suggested_question": {
          "en": "Can you help me move this desk?",
          "vi": "Bạn giúp tôi di chuyển cái bàn này được không?"
        },
        "text": {
          "en": "Sure, no problem.",
          "vi": "Chắc chắn rồi, không vấn đề gì."
        }
      },
      {
        "label": "B",
        "why": "Trả lời về số lượng (Quantity), thường dùng cho câu hỏi 'How many'.",
        "context_intro": "Câu này sẽ ĐÚNG nếu câu hỏi là:",
        "suggested_question": {
          "en": "How many items are in the delivery?",
          "vi": "Đợt giao hàng này có bao nhiêu kiện vậy?"
        },
        "text": {
          "en": "About twelve shipping boxes.",
          "vi": "Khoảng 12 thùng hàng."
        }
      }
    ],
    "vocabulary": [
      {
        "word": "warehouse",
        "ipa": "/ˈweəhaʊs/",
        "meaning": "kho hàng"
      },
      {
        "word": "arrive",
        "ipa": "/əˈraɪv/",
        "meaning": "đến nơi"
      }
    ]
  }
}

{
  "questionNo": "9",
  "type": "12_Tag",
  "question": {
    "en": "There's a nice park nearby, right?",
    "vi": "Gần đây có một cái công viên khá đẹp, đúng không?"
  },
  "options": [
    {
      "label": "A",
      "en": "Did you order paper for the copier?",
      "vi": "Bạn đã đặt mua giấy cho máy photocopy chưa?"
    },
    {
      "label": "B",
      "en": "Yes—it's next to Greendale Lake.",
      "vi": "Đúng vậy — nó nằm ngay cạnh hồ Greendale."
    },
    {
      "label": "C",
      "en": "They're in the parking garage.",
      "vi": "Chúng ở trong nhà để xe."
    }
  ],
  "correctAnswer": "B",
  "explanation": {
    "correct": {
      "why": "Câu hỏi đuôi '..., right?' dùng để xác nhận thông tin. Đáp án B xác nhận bằng 'Yes' và cung cấp thêm chi tiết vị trí cụ thể."
    },
    "incorrect": [
      {
        "label": "A",
        "why": "Đây là một câu hỏi khác, không liên quan đến bối cảnh công viên hay vị trí.",
        "context_intro": "Câu này sẽ ĐÚNG nếu là một phần của hội thoại:",
        "suggested_question": {
          "en": "We've run out of stationery.",
          "vi": "Chúng ta hết đồ dùng văn phòng rồi."
        },
        "text": {
          "en": "Did you order paper for the copier?",
          "vi": "Thế bạn đã đặt mua giấy cho máy photocopy chưa?"
        }
      },
      {
        "label": "C",
        "why": "Sử dụng đại từ 'They' không khớp với chủ ngữ 'a nice park' (số ít).",
        "context_intro": "Câu này sẽ ĐÚNG nếu câu hỏi là:",
        "suggested_question": {
          "en": "Where did the visitors leave their cars?",
          "vi": "Khách tham quan để xe ở đâu rồi?"
        },
        "text": {
          "en": "They're in the parking garage.",
          "vi": "Chúng (những chiếc xe) ở trong nhà để xe."
        }
      }
    ],
    "vocabulary": [
      {
        "word": "nearby",
        "ipa": "/ˌnɪəˈbaɪ/",
        "meaning": "gần đây, lân cận"
      },
      {
        "word": "parking garage",
        "ipa": "/ˈpɑːkɪŋ ˈɡærɑːʒ/",
        "meaning": "nhà để xe cao tầng"
      }
    ]
  }
}

