      {
        "word": "Finance analyst",
        "ipa": "/faɪˈnæns ˈænəlɪst/",
        "meaning": "Chuyên viên phân tích tài chính"
      },
      {
        "word": "Competent",
        "ipa": "/ˈkɒmpɪtənt/",
        "meaning": "Có năng lực, thạo việc"
      }
    ]
  }
}

{
  "questionNo": "12",
  "type": "3_Offer_Suggestion_Command",
  "question": {
    "en": "Let's go on the company retreat.",
    "vi": "Chúng ta hãy đi nghỉ dưỡng cùng công ty đi."
  },
  "options": [
    {
      "label": "A",
      "en": "Oh, did he?",
      "vi": "Ồ, anh ấy đã làm vậy sao?"
    },
    {
      "label": "B",
      "en": "Yes, that's a good idea.",
      "vi": "Vâng, ý kiến đó hay đấy."
    },
    {
      "label": "C",
      "en": "He tried to solve that problem.",
      "vi": "Anh ấy đã cố gắng giải quyết vấn đề đó."
    }
  ],
  "correctAnswer": "B",
  "explanation": {
    "correct": {
      "why": "Câu gốc là một lời đề nghị (Let's...). Đáp án B là một câu đồng thuận trực tiếp và phổ biến đối với các lời gợi ý."
    },
    "incorrect": [
      {
        "label": "A",
        "why": "Sử dụng đại từ 'he' không rõ nguồn gốc và trợ động từ 'did' không khớp với cấu trúc đề nghị 'Let's'.",
        "context_intro": "Câu này sẽ ĐÚNG nếu câu hỏi là:",
        "suggested_question": {
          "en": "The manager decided to cancel the meeting.",
          "vi": "Quản lý đã quyết định hủy buổi họp rồi."
        },
        "text": {
          "en": "Oh, did he?",
          "vi": "Ồ, anh ấy đã làm vậy sao?"
        }
      },
      {
        "label": "C",
        "why": "Đáp án này kể về hành động của một người thứ ba trong quá khứ, không liên quan đến việc đi nghỉ dưỡng.",
        "context_intro": "Câu này sẽ ĐÚNG nếu câu hỏi là:",
        "suggested_question": {
          "en": "Why is the technician still at the server room?",
          "vi": "Tại sao anh thợ kỹ thuật vẫn còn ở phòng máy chủ vậy?"
        },
        "text": {
          "en": "He tried to solve that problem.",
          "vi": "Anh ấy đã cố gắng giải quyết vấn đề đó."
        }
      }
    ],
    "vocabulary": [
      {
        "word": "Company retreat",
        "ipa": "/ˈkʌmpəni rɪˈtriːt/",
        "meaning": "Kỳ nghỉ dưỡng/du lịch của công ty"
      }
    ]
  }
}

passageText:
{
  "passages": [
    {
      "category": "Conversation 32-34",
      "html_content": "<div data-sid='s1'><b>W-Am:</b> Hey, Oliver.</div><div data-sid='s2'>Did you see the focus group results for <sup>32</sup> <b>our new spicy cheddar cheese?</b></div><div data-sid='s3'>Everyone really liked it.</div><div data-sid='s4'><b>M-Cn:</b> Yes.</div><div data-sid='s5'>It should be a great addition to our company's line of cheeses.</div><div data-sid='s6'><b>W-Am:</b> Several people mentioned that they'd like to use it in recipes—to add to sauces, for example.</div><div data-sid='s7'><b>M-Cn:</b> <sup>33</sup> <b>So maybe we should consider selling a shredded version that would melt easily when cooked.</b></div><div data-sid='s8'><b>W-Am:</b> I'm sure we could do that.</div><div data-sid='s9'><sup>34</sup> <b>I'll get in touch with the production manager with that request.</b></div>",
      "translation_map": {
        "s1": "<b>Nữ (Mỹ):</b> Này, Oliver.",
        "s2": "Cô đã xem kết quả khảo sát nhóm tập trung cho <sup>32</sup> <b>sản phẩm phô mai cheddar cay mới của chúng ta chưa?</b>",
        "s3": "Mọi người thực sự rất thích nó.",
        "s4": "<b>Nam (Trung Quốc):</b> Có chứ.",
        "s5": "Nó sẽ là một sự bổ sung tuyệt vời cho dòng sản phẩm phô mai của công ty chúng ta.",
        "s6": "<b>Nữ (Mỹ):</b> Một vài người đã đề cập rằng họ muốn sử dụng nó trong các công thức nấu ăn—ví dụ như thêm vào nước sốt.",
        "s7": "<b>Nam (Trung Quốc):</b> <sup>33</sup> <b>Vì vậy, có lẽ chúng ta nên cân nhắc việc bán phiên bản phô mai bào để nó dễ tan chảy hơn khi nấu.</b>",
        "s8": "<b>Nữ (Mỹ):</b> Tôi chắc chắn rằng chúng ta có thể làm được việc đó.",
        "s9": "<sup>34</sup> <b>Tôi sẽ liên lạc với quản lý sản xuất về yêu cầu đó.</b>"
      }
    }
  ],
  "questions": [
    {
      "questionNo": 32,
      "text": "What type of food product does the speakers' company sell?",
      "options": {
        "A": "Candy",
        "B": "Cheese",
        "C": "Bread",
        "D": "Pasta"
      },
      "correct": "B",
      "evidence_sids": [
        "s2",
        "s5"
      ],
      "explanation": {
        "vi": "Công ty của những người nói bán loại sản phẩm thực phẩm nào?",
        "options_vn": {
          "A": "Kẹo",
          "B": "Phô mai",
          "C": "Bánh mì",
          "D": "Mì Ý"
        },
        "why_correct": "Người phụ nữ đề cập đến 'our new spicy cheddar cheese' (phô mai cheddar cay mới của chúng ta) và người đàn ông xác nhận nó thuộc 'company's line of cheeses' (dòng phô mai của công ty).",
        "why_wrong": {
          "A": "Kẹo không được nhắc đến trong đoạn hội thoại.",
          "C": "Bánh mì không được nhắc đến trong đoạn hội thoại.",
          "D": "Mì Ý không được nhắc đến trong đoạn hội thoại."
        }
      }
    },
    {
      "questionNo": 33,
      "text": "What does the man suggest?",
      "options": {
        "A": "Lowering prices",
        "B": "Hiring more workers",
        "C": "Publishing a recipe",
        "D": "Offering additional options"
      },
      "correct": "D",
      "evidence_sids": [
        "s7"
      ],
      "explanation": {
        "vi": "Người đàn ông gợi ý điều gì?",
        "options_vn": {
          "A": "Giảm giá",
          "B": "Thuê thêm nhân viên",
          "C": "Xuất bản một công thức nấu ăn",
          "D": "Cung cấp thêm các lựa chọn bổ sung"
        },
        "why_correct": "Người đàn ông gợi ý 'selling a shredded version' (bán phiên bản dạng bào nhỏ), đây chính là việc cung cấp thêm một lựa chọn sản phẩm khác (additional option) bên cạnh sản phẩm gốc.",
        "why_wrong": {
          "A": "Không có thông tin nào về việc giảm giá.",
          "B": "Không có thông tin nào về việc tuyển thêm người làm.",
          "C": "Dù có nhắc đến việc khách hàng muốn dùng phô mai cho các công thức (recipes), nhưng người đàn ông không gợi ý xuất bản chúng."
        }
      }
    },
    {
      "questionNo": 34,
      "text": "What does the woman say she will do?",
      "options": {
        "A": "Send a schedule update",
        "B": "Contact a production manager",
        "C": "Visit the company headquarters",
        "D": "Plan an advertising campaign"
      },
      "correct": "B",
      "evidence_sids": [
        "s9"
      ],
      "explanation": {
        "vi": "Người phụ nữ nói cô ấy sẽ làm gì?",
